modules.modern:
// Constants lifted from PAYROLL01.CBL WORKING-STORAGE WS-TAX-BANDS (lines 82-88)
// and WS-NI-MAIN-RATE, WS-NI-UPPER-RATE (lines 87-88). Original comment context:
// line 82: 05 WS-BAND1-LIM PIC 9(4)V99 VALUE 242.00.
// line 83: 05 WS-BAND2-LIM PIC 9(4)V99 VALUE 967.00.
// line 84: 05 WS-BAND2-RATE PIC V99 VALUE .20.  (tax, not used here)
// line 85: 05 WS-BAND3-RATE PIC V99 VALUE .40.  (tax, not used here)
// line 87: 05 WS-NI-MAIN-RATE  PIC V99 VALUE .08.
// line 88: 05 WS-NI-UPPER-RATE PIC V99 VALUE .02.
export const NI_CONFIG = {
  /** Weekly personal allowance (0% band) – pence */
  band1LimitPence: 24200,           // line 82
  /** Upper earnings limit for main rate – pence */
  band2LimitPence: 96700,           // line 83
  /** NI main rate (8%) as integer numerator/denominator for pence arithmetic */
  mainRateNumerator: 8,             // line 87 (0.08 * 100)
  /** NI upper rate (2%) */
  upperRateNumerator: 2,            // line 88 (0.02 * 100)
  rateDenominator: 100
} as const;

/**
 * Compute weekly National Insurance contribution in whole pence (integer),
 * using the pension-adjusted taxable income (WS-TAXABLE).
 *
 * Replicates the logic of COBOL paragraph 400-NI with the business change applied:
 * - NI is now computed on pension-adjusted taxable income, not gross pay.
 * - Uses half‑up rounding (COBOL ROUNDED semantic) across the whole expression.
 * - Thresholds unchanged; usage of WS-TAXABLE replaces WS-GROSS.
 *
 * @param taxableIncomePence - taxable pay in pence (WS-TAXABLE)
 * @returns NI contribution in pence, rounded to 2 decimal places of pounds (i.e., integer pence)
 */
export function computeNi(taxableIncomePence: number): number {
  const { band1LimitPence, band2LimitPence, mainRateNumerator, upperRateNumerator, rateDenominator } = NI_CONFIG;

  if (taxableIncomePence <= band1LimitPence) {
    return 0;
  }

  if (taxableIncomePence <= band2LimitPence) {
    // NI = (taxable - band1) * 8 / 100, result rounded to nearest pence (half up)
    const diff = taxableIncomePence - band1LimitPence;
    return Math.round(diff * mainRateNumerator / rateDenominator);
  }

  // Upper band: NI = (band2 - band1) * 8/100 + (taxable - band2) * 2/100, rounded once
  const bandDiff = band2LimitPence - band1LimitPence;
  const mainPart = bandDiff * mainRateNumerator;
  const upperPart = (taxableIncomePence - band2LimitPence) * upperRateNumerator;
  return Math.round((mainPart + upperPart) / rateDenominator);
}

modules.tests:
import { describe, it, expect } from 'vitest';
import { computeNi, NI_CONFIG } from './ni-calc';

describe('400-NI replacement – characterization and new behaviour', () => {
  // --------------- CHARACTERIZATION (behaviour that MUST NOT change) ---------------
  // These cases exercise the path where pension contribution is zero, so WS-TAXABLE == WS-GROSS.
  // The new code must yield identical NI to the legacy gross‑basis calculation.

  it('zero NI when taxable pay at band1 threshold (242.00)', () => {
    // taxable = 24200 pence = £242.00
    // legacy and new: 242.00 <= 242.00 → NI 0
    expect(computeNi(24200)).toBe(0);
  });

  it('zero NI for 242.01 – rounding causes no pence paid', () => {
    // taxable = 24201 pence (1 pence above band1)
    // diff = 1, NI = 1 * 8 / 100 = 0.08 pence → round half‑up to 0
    expect(computeNi(24201)).toBe(0);
  });

  it('first pence at 242.12 – boundary where rounding produces 1 penny', () => {
    // taxable = 24212 pence, diff = 12
    // 12 * 8 / 100 = 0.96 pence → Math.round(0.96) = 1 (half‑up)
    expect(computeNi(24212)).toBe(1);
  });

  it('main band, no upper band: £500.00 gross, zero pension', () => {
    const grossPence = 50000; // £500.00
    // taxable = gross (no pension) = 50000
    // diff = 50000 - 24200 = 25800
    // NI = 25800 * 0.08 = 2064.00 → 2064 pence
    // hand calc: 25800 / 100 * 8 = 2064 exactly
    expect(computeNi(grossPence)).toBe(2064);
  });

  it('upper band: £1000.00 gross, zero pension', () => {
    const grossPence = 100000; // £1000.00
    // taxable = 100000
    // band diff = 96700 - 24200 = 72500
    // main part = 72500 * 0.08 = 5800.00
    // excess = 100000 - 96700 = 3300
    // upper part = 3300 * 0.02 = 66.00
    // total = 5866.00 → 5866 pence
    expect(computeNi(grossPence)).toBe(5866);
  });

  it('upper band, rounding edge: £967.01 gross, zero pension – no upper band yet', () => {
    const grossPence = 96701; // £967.01, one pence above band1 but below band2
    // Actually band2 = 96700, so taxable 96701 is > band2? Wait: 96701 > 96700, so it is upper band.
    // So it falls into else branch. Let's recalc:
    // taxable = 96701, band2 = 96700, band1 = 24200
    // bandDiff = 72500; main part = 72500 * 8 = 580000 (numerator)
    // excess = 96701 - 96700 = 1; upper part = 1 * 2 = 2
    // sum = 580002; divide by 100 = 5800.02 → Math.round => 5800 pence
    expect(computeNi(grossPence)).toBe(5800);
  });

  // --------------- NEW BEHAVIOUR (pension reduces NI base) ---------------

  it('main band: £500 gross, 5% pension -> NI computed on £475', () => {
    const grossPence = 50000;
    const pensionPence = 2500; // 5% of 50000
    const taxablePence = grossPence - pensionPence; // 47500
    // diff = 47500 - 24200 = 23300
    // NI = 23300 * 0.08 = 1864.00 → 1864 pence
    expect(computeNi(taxablePence)).toBe(1864);
  });

  it('reduced benefit: same employee as above compared to old gross NI', () => {
    const oldNi = computeNi(50000); // on gross 50000 → 2064 pence
    const newNi = computeNi(47500); // on taxable 47500 → 1864 pence
    expect(oldNi).toBe(2064);
    expect(newNi).toBe(1864);
    expect(newNi).toBeLessThan(oldNi);
  });

  it('upper band: £1000 gross, 5% pension -> NI on £950', () => {
    const taxablePence = 100000 - 5000; // 95000
    // 95000 < 96700, so main band only
    // diff = 95000 - 24200 = 70800
    // NI = 70800 * 0.08 = 5664.00 → 5664 pence
    expect(computeNi(taxablePence)).toBe(5664);
  });

  it('legacy scheme (G6/G7, 6.5%) at upper band reduces NI further', () => {
    const grossPence = 120000; // £1200.00
    const pensionPence = Math.round(grossPence * 0.065); // 7800 pence
    const taxablePence = grossPence - pensionPence; // 112200
    // taxable 112200 > 96700, upper band
    // bandDiff = 72500, main part = 580000
    // excess = 112200 - 96700 = 15500
    // upper part = 15500 * 2 = 31000
    // sum = 611000, /100 = 6110.00 → 6110 pence
    // Legacy 400-NI on gross 120000 would have been:
    // gross 120000, bandDiff 72500*0.08=5800, excess 120000-96700=23300*0.02=466, total 6266
    // Hand check: 5800+466=6266 pence, reduction = 156 pence
    expect(computeNi(taxablePence)).toBe(6110);
  });

  it('opt‑out flag => taxable = gross, NI identical to legacy', () => {
    const grossPence = 75000; // £750.00
    // opt-out -> pension=0, taxable = gross
    expect(computeNi(grossPence)).toBe(computeNi(grossPence)); // self‑consistency
    // Verify known value: 75000-24200=50800 * 0.08 = 4064
    expect(computeNi(grossPence)).toBe(4064);
  });

  it('exactly at band2 threshold after pension gives main band NI only', () => {
    const taxablePence = NI_CONFIG.band2LimitPence; // 96700
    // Should be main band NI: 96700-24200=72500 * 0.08 = 5800
    expect(computeNi(taxablePence)).toBe(5800);
  });

  it('negative taxable income (should never happen) returns 0', () => {
    // Defensive: if pension > gross somehow
    expect(computeNi(-100)).toBe(0);
  });
});
